// RegisterAccount is the resolver for the registerAccount field.
func (r *mutationResolver) RegisterAccount(ctx context.Context, email string, username string, password string, pgpKey *string) (*model.User, error) {
	// Note: this resolver is used with anonymous internal auth, so most of the
	// fields in auth.ForContext(ctx) are invalid.
	valid := valid.New(ctx)
	valid.Expect(len(username) >= 2 && len(username) <= 30,
		"Username must be between 2 and 30 characters in length.").
		WithField("username")
	valid.Expect(usernameRE.MatchString(username),
		"Username must use only lowercase letters, digits, underscores, and dashes, and must start with a letter or underscore.").
		WithField("username")
	blacklist := sort.SearchStrings(usernameBlacklist, username)
	valid.Expect(blacklist >= len(usernameBlacklist) ||
		usernameBlacklist[blacklist] != username,
		"This username is not available").
		WithField("username")

	valid.Expect(len(email) <= 256,
		"Email cannot be greater than 256 characters in length.").
		WithField("email")
	valid.Expect(strings.ContainsRune(email, '@'),
		"This is not a valid email address.").
		WithField("email")
	parts := strings.Split(email, "@")
	if len(parts) == 2 {
		blacklist := sort.SearchStrings(emailBlacklist, strings.ToLower(parts[1]))
		valid.Expect(blacklist >= len(emailBlacklist) ||
			emailBlacklist[blacklist] != email,
			"Accounts are not permitted to use this email provider.").
			WithField("email")
	}

	valid.Expect(len(password) <= 512,
		"Password must be no more than 512 characters in length.").
		WithField("password")
	conf := config.ForContext(ctx)
	env, ok := conf.Get("sr.ht", "environment")
	if ok && env == "production" {
		strength := zxcvbn.PasswordStrength(password, []string{
			username,
			email,
			"sourcehut",
			"sr.ht",
		})
		valid.Expect(strength.Score >= 3,
			"This password is too weak. Longer passwords are better than complicated passwords. The use of a password manager is strongly recommended.").
			WithField("password")
	}

	var pkey *packet.PublicKey
	if pgpKey != nil {
		// Note: You may also need to update the CreatePGPKey resolver if you
		// are working with this code.
		keys, err := openpgp.ReadArmoredKeyRing(strings.NewReader(*pgpKey))
		valid.
			Expect(err == nil, "Invalid PGP key format: %v", err).
			WithField("pgpKey").
			And(len(keys) == 1, "Expected one key, found %d", len(keys)).
			WithField("pgpKey")
		if !valid.Ok() {
			return nil, nil
		}

		entity := keys[0]
		valid.Expect(entity.PrivateKey == nil, "There's a private key in here, yikes!")

		pkey = entity.PrimaryKey
		valid.Expect(pkey != nil && pkey.CanSign(),
			"No public keys suitable for signing found.")
	}

	if !valid.Ok() {
		return nil, nil
	}

	// bcrypt truncates to 72 characters
	if len(password) > 72 {
		password = password[:72]
	}

	pwhash, err := bcrypt.GenerateFromPassword(
		[]byte(password), bcrypt.DefaultCost)
	if err != nil {
		panic(err)
	}

	token := emails.GenToken()

	var user model.User
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		var reserved string
		row := tx.QueryRowContext(ctx, `
			SELECT * FROM reserved_usernames WHERE username = $1;
		`, username)
		if err := row.Scan(&reserved); err == nil {
			valid.Expect(false, "This username is not available").
				WithField("username")
			return errors.New("placeholder") // Roll back transaction
		} else if err == sql.ErrNoRows {
			// no-op
		} else {
			return err
		}

		row = tx.QueryRowContext(ctx, `
			INSERT INTO "user" (
				created, updated, user_type,
				username, email, password
			) VALUES (
				NOW() at time zone 'utc',
				NOW() at time zone 'utc',
				'PENDING',
				$1, $2, $3
			)
			RETURNING id, created, updated, username, email, user_type;
		`, username, email, string(pwhash))

		if err := row.Scan(&user.ID, &user.Created, &user.Updated,
			&user.Username, &user.Email, &user.UserType); err != nil {
			if err, ok := err.(*pq.Error); ok &&
				err.Code == "23505" && // unique_violation
				err.Constraint == "user_username_key" {
				valid.Error("This username is already in use.").
					WithField("username")
				return errors.New("placeholder") // To rollback the transaction
			}
			if err, ok := err.(*pq.Error); ok &&
				err.Code == "23505" && // unique_violation
				err.Constraint == "user_email_key" {
				valid.Error("This email address is already in use.").
					WithField("email")
				return errors.New("placeholder") // To rollback the transaction
			}
			return err
		}

		_, err = tx.ExecContext(ctx, `
			INSERT INTO user_registration (
				user_id, token
			) VALUES ($1, $2);
		`, user.ID, token)
		if err != nil {
			return err
		}

		addr := server.RemoteAddr(ctx)
		_, err = tx.ExecContext(ctx, `
			INSERT INTO audit_log_entry (
				created, user_id, ip_address, event_type, details
			) VALUES (
				NOW() at time zone 'utc',
				$1, $2, $3, $4
			);`, user.ID, addr,
			"account registered",
			fmt.Sprintf("registered ~%s (%s)", user.Username, user.Email))
		if err != nil {
			panic(err)
		}

		if pkey != nil {
			row = tx.QueryRowContext(ctx, `
					INSERT INTO pgpkey (
						created, user_id, key, fingerprint
					) VALUES (
						NOW() at time zone 'utc',
						$1, $2, $3
					) RETURNING id;
				`, user.ID, *pgpKey, pkey.Fingerprint[:])
			var id int
			if err := row.Scan(&id); err != nil {
				if err, ok := err.(*pq.Error); ok &&
					err.Code == "23505" && // unique_violation
					err.Constraint == "ix_pgpkey_fingerprint" {
					valid.Error("We already have this PGP key on file, and duplicates are not allowed.").
						WithField("pgpKey")
					return errors.New("placeholder")
				}
				return err
			}

			if _, err := tx.ExecContext(ctx, `
					UPDATE "user" SET pgp_key_id = $1 WHERE id = $2;
				`, id, user.ID); err != nil {
				return err
			}
		}

		if endpoint, ok := conf.Get("abused", "endpoint"); ok {
			token, _ := conf.Get("abused", "token")
			client := oauth2.Client{}
			hclient := client.NewHTTPClient(&oauth2.TokenResp{
				AccessToken: token,
				TokenType:   oauth2.TokenTypeBearer,
			})
			gclient := gqlclient.New(endpoint, hclient)
			rate := "registration"
			ipAddr := auth.ForContext(ctx).IPAddress
			sample := abused.Sample{
				IpAddress: &ipAddr,
				Email:     &email,
				Username:  &username,
				RateLimit: &rate,
			}
			analysis, err := abused.Analyze(gclient, ctx, sample)
			if err != nil {
				log.Printf("abused returned error: %s", err.Error())
				tx.Rollback()
				return err
			}
			if analysis.Outcome != abused.OutcomePass {
				support, _ := conf.Get("sr.ht", "owner-email")
				incidentCode, _ := uuid.NewRandom()
				valid.Error("Our abuse prevention systems have flagged your account registration. Contact support for assistance at %s. Your incident code is: %s",
					support, incidentCode.String())
				input, _ := json.Marshal(&sample)
				result, _ := json.Marshal(analysis)
				log.Printf("abused hit [%s] %s => %s", incidentCode.String(),
					string(input), string(result))
				tx.Rollback()
				return fmt.Errorf("abused hit")
			}
		}

		return nil
	}); err != nil {
		if !valid.Ok() {
			return nil, nil
		}
		return nil, err
	}

	log.Printf("Registered new account: ~%s <%s> (%d)",
		user.Username, user.Email, user.ID)
	emails.SendRegistrationConfirmation(ctx, &user, pgpKey, token)
	return &user, nil
}

// ResetPassword is the resolver for the resetPassword field.
func (r *mutationResolver) ResetPassword(ctx context.Context, email string) (*int, error) {
	token := emails.GenToken()

	user, err := loaders.ForContext(ctx).UsersByEmail.Load(email)
	if err != nil {
		return nil, nil
	}

	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		_, err := tx.ExecContext(ctx, `
			INSERT INTO user_password_change (
				user_id, token
			) VALUES ($1, $2)
			ON CONFLICT ON CONSTRAINT user_password_change_user_id_key
			DO UPDATE SET token = $2, issued = NOW() at time zone 'utc';
		`, user.ID, token)
		return err
	}); err != nil {
		panic(err)
	}

	pgpKey, err := emails.PGPKeyForUser(ctx, user)
	if err != nil {
		// Ignore error, worst case the notification email is unencrypted
		log.Printf("failed to get PGP key for user %d: %s", user.ID, err.Error())
	}

	emails.SendPasswordResetConfirmation(ctx, user, pgpKey, token)

	populateAuthCtx(ctx, user)
	recordAuditLog(ctx, "password reset", "Requested password reset")

	return nil, nil
}

// ConfirmRegistration is the resolver for the confirmRegistration field.
func (r *mutationResolver) ConfirmRegistration(ctx context.Context, token string) (*model.User, error) {
	var user model.User

	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		var uid int
		row := tx.QueryRowContext(ctx, `
			DELETE FROM user_registration
			WHERE token = $1
			RETURNING user_id;
		`, token)

		if err := row.Scan(&uid); err != nil {
			return err
		}

		row = tx.QueryRowContext(ctx, `
			UPDATE "user"
			SET
				user_type = 'USER',
				updated = NOW() at time zone 'utc'
			WHERE id = $1
			RETURNING id, created, updated, username, email, user_type;
		`, uid)

		return row.Scan(&user.ID, &user.Created, &user.Updated,
			&user.Username, &user.Email, &user.UserType)
	}); err != nil {
		if err == sql.ErrNoRows {
			return nil, ErrInvalidEmailToken
		}
		return nil, err
	}

	log.Printf("Confirmed account registration for %d:~%s",
		user.ID, user.Username)
	return &user, nil
}

// ConfirmEmailChange is the resolver for the confirmEmailChange field.
func (r *mutationResolver) ConfirmEmailChange(ctx context.Context, token string) (*model.User, error) {
	var user model.User

	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		var (
			uid      int
			newEmail string
		)
		row := tx.QueryRowContext(ctx, `
			DELETE FROM user_email_change
			WHERE token = $1
			RETURNING user_id, new_email;
		`, token)

		if err := row.Scan(&uid, &newEmail); err != nil {
			return err
		}

		row = tx.QueryRowContext(ctx, `
			UPDATE "user"
			SET
				updated = NOW() at time zone 'utc',
				email = $2
			WHERE id = $1
			RETURNING id, created, updated, username, email, user_type;
		`, uid, newEmail)

		return row.Scan(&user.ID, &user.Created, &user.Updated,
			&user.Username, &user.Email, &user.UserType)
	}); err != nil {
		if err == sql.ErrNoRows {
			return nil, ErrInvalidEmailToken
		}
		return nil, err
	}

	log.Printf("Updated email address for %d:~%s: now %s",
		user.ID, user.Username, user.Email)

	conf := config.ForContext(ctx)
	siteName, ok := conf.Get("sr.ht", "site-name")
	if !ok {
		panic(fmt.Errorf("expected [sr.ht]site-name in config"))
	}

	populateAuthCtx(ctx, &user)
	webhooks.DeliverProfileUpdate(ctx, &user)
	webhooks.DeliverLegacyProfileUpdate(ctx, &user)
	recordAuditLog(ctx, "Email change confirmed",
		fmt.Sprintf("Email change confirmed: %s", user.Email))
	sendSecurityNotification(ctx,
		fmt.Sprintf("Your email address has been updated on %s", siteName),
		"Your new email address is confirmed.")

	return &user, nil
}

// ConfirmPasswordChange is the resolver for the confirmPasswordChange field.
func (r *mutationResolver) ConfirmPasswordChange(ctx context.Context, token string, newPassword string) (*model.User, error) {
	var user model.User

	// bcrypt truncates to 72 characters
	if len(newPassword) > 72 {
		newPassword = newPassword[:72]
	}

	pwhash, err := bcrypt.GenerateFromPassword(
		[]byte(newPassword), bcrypt.DefaultCost)
	if err != nil {
		panic(err)
	}

	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		var uid int
		row := tx.QueryRowContext(ctx, `
			DELETE FROM user_password_change
			WHERE
				token = $1 AND
				issued > now() at time zone 'utc' - interval '48 hours'
			RETURNING user_id;
		`, token)

		if err := row.Scan(&uid); err != nil {
			return err
		}

		row = tx.QueryRowContext(ctx, `
			UPDATE "user"
			SET password = $2
			WHERE id = $1
			RETURNING id, created, updated, username, email, user_type;
		`, uid, string(pwhash))

		return row.Scan(&user.ID, &user.Created, &user.Updated,
			&user.Username, &user.Email, &user.UserType)
	}); err != nil {
		if err == sql.ErrNoRows {
			return nil, ErrInvalidEmailToken
		}
		return nil, err
	}

	log.Printf("Reset password for %d:~%s", user.ID, user.Username)

	conf := config.ForContext(ctx)
	siteName, ok := conf.Get("sr.ht", "site-name")
	if !ok {
		panic(fmt.Errorf("expected [sr.ht]site-name in config"))
	}

	populateAuthCtx(ctx, &user)
	recordAuditLog(ctx, "password reset", "Password reset completed")
	sendSecurityNotification(ctx,
		fmt.Sprintf("Your %s password was reset", siteName),
		"Your password has been reset.")

	return &user, nil
}

// EnableTOTP is the resolver for the enableTOTP field.
func (r *mutationResolver) EnableTOTP(ctx context.Context, secret string) (*model.TOTPConfig, error) {
	var (
		totpConfig model.TOTPConfig
		hashes     [10]string
	)

	conf := config.ForContext(ctx)
	siteName, ok := conf.Get("sr.ht", "site-name")
	if !ok {
		panic(fmt.Errorf("expected [sr.ht]site-name in config"))
	}

	// Generate recovery codes
	for i := 0; i < len(hashes); i++ {
		var bytes [10]byte
		n, err := rand.Read(bytes[:])
		if err != nil || n != len(bytes) {
			panic(err)
		}
		code := base32.StdEncoding.
			WithPadding(base32.NoPadding).
			EncodeToString(bytes[:])
		totpConfig.RecoveryCodes = append(totpConfig.RecoveryCodes, code)

		hash, err := bcrypt.GenerateFromPassword(
			[]byte(code), bcrypt.DefaultCost)
		if err != nil {
			panic(err)
		}
		hashes[i] = string(hash)
	}
	extra, err := json.Marshal(hashes)
	if err != nil {
		panic(err)
	}

	userID := auth.ForContext(ctx).UserID
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		_, err := tx.ExecContext(ctx, `
		INSERT INTO user_auth_factor (
			created,
			updated,
			factor_type,
			user_id,
			secret,
			extra
		) VALUES (
			NOW() at time zone 'utc',
			NOW() at time zone 'utc',
			'totp',
			$1,
			$2,
			$3
		)
		ON CONFLICT ON CONSTRAINT user_auth_factor_user_id_key
		DO UPDATE SET secret = $2, extra = $3;`,
			userID, []byte(secret), extra)
		return err
	}); err != nil {
		return nil, err
	}

	recordAuditLog(ctx, "Enable TOTP", "Enabled two-factor authentication")
	sendSecurityNotification(ctx,
		fmt.Sprintf("TOTP has been enabled for your %s account", siteName),
		"Two-factor authentication (with TOTP) was enabled")

	return &totpConfig, nil
}

// RegisterOAuthClient is the resolver for the registerOAuthClient field.
func (r *mutationResolver) RegisterOAuthClient(ctx context.Context, redirectURI string, clientName string, clientDescription *string, clientURL *string) (*model.OAuthClientRegistration, error) {
	var seed [64]byte
	n, err := rand.Read(seed[:])
	if err != nil || n != len(seed) {
		panic(err)
	}
	secret := base64.StdEncoding.EncodeToString(seed[:])
	hash := sha512.Sum512(seed[:])
	partial := secret[:8]
	clientID, err := uuid.NewRandom()
	if err != nil {
		panic(err)
	}

	var id int
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
				INSERT INTO oauth2_client (
					created, updated,
					owner_id,
					client_uuid,
					client_secret_hash,
					client_secret_partial,
					redirect_url,
					client_name, client_description, client_url
				) VALUES (
					NOW() at time zone 'utc',
					NOW() at time zone 'utc',
					$1, $2, $3, $4, $5, $6, $7, $8
				) RETURNING (id);
			`, auth.ForContext(ctx).UserID, clientID.String(),
			hex.EncodeToString(hash[:]), partial, redirectURI, clientName,
			clientDescription, clientURL)
		if err := row.Scan(&id); err != nil {
			if err == sql.ErrNoRows {
				panic(fmt.Errorf("PostgreSQL invariant broken"))
			}
			return err
		}

		return nil
	}); err != nil {
		return nil, err
	}

	recordAuditLog(ctx, "OAuth 2.0 client registered", clientID.String())

	return &model.OAuthClientRegistration{
		Client: &model.OAuthClient{
			ID:          id,
			UUID:        clientID.String(),
			RedirectURL: redirectURI,
			Name:        clientName,
			Description: clientDescription,
			URL:         clientURL,
		},
		Secret: secret,
	}, nil
}

// RevokeOAuthClient is the resolver for the revokeOAuthClient field.
func (r *mutationResolver) RevokeOAuthClient(ctx context.Context, uuid string) (*model.OAuthClient, error) {
	var oc model.OAuthClient
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		user := auth.ForContext(ctx)
		uid := user.UserID
		if user.UserType == auth.USER_TYPE_ADMIN {
			uid = -1
		}
		row := tx.QueryRowContext(ctx, `
			UPDATE oauth2_client
			SET revoked = true
			WHERE client_uuid = $1
				-- Admins can revoke any token:
				AND CASE WHEN $2 = -1 THEN true ELSE owner_id = $2 END
			RETURNING
				id, client_uuid, redirect_url,
				client_name, client_description, client_url,
				owner_id;
		`, uuid, uid)
		if err := row.Scan(&oc.ID, &oc.UUID, &oc.RedirectURL, &oc.Name,
			&oc.Description, &oc.URL, &oc.OwnerID); err != nil {
			return err
		}

		row = tx.QueryRowContext(ctx, `
			UPDATE oauth2_grant
			SET expires = now() at time zone 'utc'
			WHERE client_id = $1;
		`, oc.ID)

		if err := row.Scan(); err != nil && err != sql.ErrNoRows {
			return err
		}

		return nil
	}); err != nil {
		return nil, err
	}

	recordAuditLog(ctx, "OAuth 2.0 client revoked", oc.UUID)

	rc := redis.ForContext(ctx)
	key := fmt.Sprintf("meta.sr.ht::oauth2::client_revocations::%s", uuid)
	err := rc.Set(ctx, key, true, time.Duration(0)).Err()
	return &oc, err
}

// RevokeOAuthGrant is the resolver for the revokeOAuthGrant field.
func (r *mutationResolver) RevokeOAuthGrant(ctx context.Context, hash string) (*model.OAuthGrant, error) {
	var grant model.OAuthGrant
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
			UPDATE oauth2_grant
			SET expires = now() at time zone 'utc'
			WHERE token_hash = $1
			RETURNING id, issued, expires, token_hash, client_id;
		`, hash)
		return row.Scan(&grant.ID, &grant.Issued, &grant.Expires,
			&grant.TokenHash, &grant.ClientID)
	}); err != nil {
		return nil, err
	}

	rc := redis.ForContext(ctx)
	err := rc.Set(ctx,
		fmt.Sprintf("meta.sr.ht::oauth2::grant_revocations::%s", hash),
		true, grant.Expires.Sub(time.Now().UTC())).Err()
	if err != nil {
		return nil, err
	}

	recordAuditLog(ctx, "OAuth 2.0 grant revoked", "OAuth 2.0 grant revoked")

	return &grant, nil
}

// IssuePersonalAccessToken is the resolver for the issuePersonalAccessToken field.
func (r *mutationResolver) IssuePersonalAccessToken(ctx context.Context, grants *string, comment *string) (*model.OAuthPersonalTokenRegistration, error) {
	issued := time.Now().UTC()
	expires := issued.Add(366 * 24 * time.Hour)

	user := auth.ForContext(ctx)
	grant := auth.BearerToken{
		Version:  auth.TokenVersion,
		Expires:  auth.ToTimestamp(expires),
		Grants:   "",
		Username: user.Username,
		ClientID: "",
	}
	if grants != nil {
		grant.Grants = *grants
	}
	token := grant.Encode()
	hash := sha512.Sum512([]byte(token))
	tokenHash := hex.EncodeToString(hash[:])

	var id int
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
			INSERT INTO oauth2_grant
			(issued, expires, comment, token_hash, user_id, grants)
			VALUES ($1, $2, $3, $4, $5, $6)
			RETURNING (id);
		`, issued, expires, comment, tokenHash, user.UserID, grant.Grants)

		if err := row.Scan(&id); err != nil {
			if err == sql.ErrNoRows {
				panic(fmt.Errorf("PostgreSQL invariant broken"))
			}
			return err
		}

		return nil
	}); err != nil {
		return nil, err
	}

	recordAuditLog(ctx, "OAuth 2.0 token issued", "OAuth 2.0 token issued")

	conf := config.ForContext(ctx)
	siteName, ok := conf.Get("sr.ht", "site-name")
	if !ok {
		panic(fmt.Errorf("expected [sr.ht]site-name in config"))
	}
	sendSecurityNotification(ctx,
		fmt.Sprintf("A personal access token was issued for your %s account", siteName),
		"An OAuth 2.0 personal access token was issued for your account")

	return &model.OAuthPersonalTokenRegistration{
		Token: &model.OAuthPersonalToken{
			ID:      id,
			Issued:  issued,
			Expires: expires,
			Comment: comment,
			Grants:  &grant.Grants,
		},
		Secret: token,
	}, nil
}

// RevokePersonalAccessToken is the resolver for the revokePersonalAccessToken field.
func (r *mutationResolver) RevokePersonalAccessToken(ctx context.Context, id int) (*model.OAuthPersonalToken, error) {
	var tok model.OAuthPersonalToken
	var hash string

	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		user := auth.ForContext(ctx)
		uid := user.UserID
		if user.UserType == auth.USER_TYPE_ADMIN {
			uid = -1
		}
		row := tx.QueryRowContext(ctx, `
			UPDATE oauth2_grant
			SET expires = now() at time zone 'utc'
			WHERE id = $1 AND client_id is null
				-- Admins can revoke any token:
				AND CASE WHEN $2 = -1 THEN true ELSE user_id = $2 END
			RETURNING id, issued, expires, comment, token_hash;
		`, id, uid)

		if err := row.Scan(&tok.ID, &tok.Issued, &tok.Expires,
			&tok.Comment, &hash); err != nil {
			if err == sql.ErrNoRows {
				return gerrors.ErrNotFound
			}
			return err
		}

		return nil
	}); err != nil {
		return nil, err
	}

	rc := redis.ForContext(ctx)
	if err := rc.Set(ctx,
		fmt.Sprintf("meta.sr.ht::oauth2::grant_revocations::%s", hash),
		true, tok.Expires.Sub(time.Now().UTC())).Err(); err != nil {

		return nil, err
	}

	recordAuditLog(ctx, "OAuth 2.0 token revoked", "OAuth 2.0 token revoked")

	return &tok, nil
}

// IssueAuthorizationCode is the resolver for the issueAuthorizationCode field.
func (r *mutationResolver) IssueAuthorizationCode(ctx context.Context, clientUUID string, grants string) (string, error) {
	var seed [64]byte
	n, err := rand.Read(seed[:])
	if err != nil || n != len(seed) {
		panic(err)
	}
	hash := sha512.Sum512(seed[:])
	code := hex.EncodeToString(hash[:])[:32]

	payload := AuthorizationPayload{
		Grants:     grants,
		ClientUUID: clientUUID,
		UserID:     auth.ForContext(ctx).UserID,
	}
	data, err := json.Marshal(&payload)
	if err != nil {
		panic(err)
	}

	rc := redis.ForContext(ctx)
	if err := rc.Set(ctx,
		fmt.Sprintf("meta.sr.ht::oauth2::authorization_code::%s", code),
		data, 5*time.Minute).Err(); err != nil {
		return "", err
	}

	return code, nil
}

// IssueOAuthGrant is the resolver for the issueOAuthGrant field.
func (r *mutationResolver) IssueOAuthGrant(ctx context.Context, authorization string, clientUUID *string, clientSecret string, redirectURI *string) (*model.OAuthGrantRegistration, error) {
	key := fmt.Sprintf(
		"meta.sr.ht::oauth2::authorization_code::%s",
		authorization)

	rc := redis.ForContext(ctx)
	bytes, err := rc.Get(ctx, key).Bytes()
	if err == goredis.Nil {
		return nil, fmt.Errorf("invalid authorization code")
	} else if err != nil {
		return nil, err
	}
	if err = rc.Del(ctx, key).Err(); err != nil {
		panic(err)
	}
	var payload AuthorizationPayload
	if err = json.Unmarshal(bytes, &payload); err != nil {
		panic(err)
	}

	if clientUUID != nil && *clientUUID != payload.ClientUUID {
		return nil, fmt.Errorf("invalid client UUID")
	}

	issued := time.Now().UTC()
	expires := issued.Add(366 * 24 * time.Hour)

	user, err := loaders.ForContext(ctx).UsersByID.Load(payload.UserID)
	if err != nil {
		panic(err)
	}
	pgpKey, err := emails.PGPKeyForUser(ctx, user)
	if err != nil {
		// Ignore error, worst case the notification email is unencrypted
		log.Printf("failed to get PGP key for user %d: %s", user.ID, err.Error())
	}
	client, err := loaders.ForContext(ctx).
		OAuthClientsByUUID.Load(payload.ClientUUID)
	if err != nil {
		panic(err)
	}

	if !client.VerifyClientSecret(clientSecret) {
		return nil, fmt.Errorf("invalid client secret")
	}
	if redirectURI != nil && *redirectURI != client.RedirectURL {
		return nil, fmt.Errorf("invalid redirect URI")
	}

	grant := auth.BearerToken{
		Version:  auth.TokenVersion,
		Expires:  auth.ToTimestamp(expires),
		Grants:   payload.Grants,
		Username: user.Username,
		ClientID: payload.ClientUUID,
	}

	token := grant.Encode()
	hash := sha512.Sum512([]byte(token))
	tokenHash := hex.EncodeToString(hash[:])

	buf := make([]byte, 32)
	if _, err := rand.Read(buf); err != nil {
		panic(err)
	}
	refreshToken := base64.RawURLEncoding.EncodeToString(buf)

	hash = sha512.Sum512([]byte(refreshToken))
	refreshTokenHash := hex.EncodeToString(hash[:])

	var id int
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
			INSERT INTO oauth2_grant
			(issued, expires, token_hash, client_id, user_id, grants, refresh_token_hash)
			VALUES ($1, $2, $3, $4, $5, $6, $7)
			RETURNING (id);
		`, issued, expires, tokenHash, client.ID, user.ID, grant.Grants, refreshTokenHash)

		if err := row.Scan(&id); err != nil {
			if err == sql.ErrNoRows {
				panic(fmt.Errorf("PostgreSQL invariant broken"))
			}
			return err
		}

		return nil
	}); err != nil {
		return nil, err
	}

	recordAuditLog(ctx, "OAuth 2.0 access grant issued",
		fmt.Sprintf("%s (%s)", client.Name, client.UUID))

	conf := config.ForContext(ctx)
	siteName, ok := conf.Get("sr.ht", "site-name")
	if !ok {
		panic(fmt.Errorf("expected [sr.ht]site-name in config"))
	}
	emails.SendSecurityNotificationTo(ctx,
		user.Username, user.Email,
		fmt.Sprintf("A third party has been granted access to your %s account", siteName),
		fmt.Sprintf("An OAuth 2.0 bearer grant for your account was issued to %s", client.Name),
		pgpKey)

	return &model.OAuthGrantRegistration{
		Grant: &model.OAuthGrant{
			ID:      id,
			Issued:  issued,
			Expires: expires,
			Grants:  &grant.Grants,

			ClientID: client.ID,
		},
		Grants:       payload.Grants,
		Secret:       token,
		RefreshToken: refreshToken,
	}, nil
}

// RefreshOAuthGrant is the resolver for the refreshOAuthGrant field.
func (r *mutationResolver) RefreshOAuthGrant(ctx context.Context, refreshToken string, clientUUID string, clientSecret string, grants *string) (*model.OAuthGrantRegistration, error) {
	client, err := loaders.ForContext(ctx).OAuthClientsByUUID.Load(clientUUID)
	if err != nil {
		panic(err)
	} else if !client.VerifyClientSecret(clientSecret) {
		return nil, fmt.Errorf("invalid client secret")
	}

	hash := sha512.Sum512([]byte(refreshToken))
	refreshTokenHash := hex.EncodeToString(hash[:])

	expires := time.Now().UTC().Add(366 * 24 * time.Hour)

	buf := make([]byte, 32)
	if _, err := rand.Read(buf); err != nil {
		panic(err)
	}
	newRefreshToken := base64.RawURLEncoding.EncodeToString(buf)

	hash = sha512.Sum512([]byte(newRefreshToken))
	newRefreshTokenHash := hex.EncodeToString(hash[:])

	var (
		id       int
		issued   time.Time
		newToken string
	)
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		var prevGrants, username string
		row := tx.QueryRowContext(ctx, `
			SELECT g.id, g.issued, g.grants, u.username
			FROM oauth2_grant g
			LEFT JOIN "user" u on g.user_id = u.id
			WHERE g.client_id = $1 AND g.refresh_token_hash = $2;
		`, client.ID, refreshTokenHash)
		if err := row.Scan(&id, &issued, &prevGrants, &username); err == sql.ErrNoRows {
			return fmt.Errorf("invalid refresh token")
		} else if err != nil {
			return err
		}

		// TODO: allow removing grants
		if grants != nil && prevGrants != *grants {
			return fmt.Errorf("invalid grants")
		}
		if grants == nil {
			grants = &prevGrants
		}

		grant := auth.BearerToken{
			Version:  auth.TokenVersion,
			Expires:  auth.ToTimestamp(expires),
			Grants:   *grants,
			Username: username,
			ClientID: clientUUID,
		}
		newToken = grant.Encode()
		hash = sha512.Sum512([]byte(newToken))
		newTokenHash := hex.EncodeToString(hash[:])

		_, err := tx.ExecContext(ctx, `
			UPDATE oauth2_grant
			SET expires = $1, token_hash = $2, refresh_token_hash = $3
			WHERE id = $4;
		`, expires, newTokenHash, newRefreshTokenHash, id)
		return err
	}); err != nil {
		return nil, err
	}

	recordAuditLog(ctx, "OAuth 2.0 access grant refreshed",
		fmt.Sprintf("%s (%s)", client.Name, client.UUID))

	return &model.OAuthGrantRegistration{
		Grant: &model.OAuthGrant{
			ID:      id,
			Issued:  issued,
			Expires: expires,
			Grants:  grants,

			ClientID: client.ID,
		},
		Grants:       *grants,
		Secret:       newToken,
		RefreshToken: newRefreshToken,
	}, nil
}

// SendEmail is the resolver for the sendEmail field.
func (r *mutationResolver) SendEmail(ctx context.Context, address string, message string) (bool, error) {
	addr, err := mail.ParseAddress(address)
	if err != nil {
		return false, err
	}
	user, err := loaders.ForContext(ctx).UsersByEmail.Load(addr.Address)
	if err != nil {
		return false, err
	}
	if user == nil {
		err = emails.SendEmailNotification(ctx, addr.Name, addr.Address, message, nil)
	} else {
		key, err_ := emails.PGPKeyForUser(ctx, user)
		if err_ != nil {
			// Ignore error, worst case the notification email is unencrypted
			log.Printf("failed to get PGP key for user %d: %s", user.ID, err_.Error())
		}
		err = emails.SendEmailNotification(ctx, user.Username, user.Email, message, key)
	}
	return err == nil, err
}

// DeleteUser is the resolver for the deleteUser field.
func (r *mutationResolver) DeleteUser(ctx context.Context, reserve bool) (int, error) {
	user := auth.ForContext(ctx)
	account.Delete(ctx, user.UserID, user.Username, reserve)
	return user.UserID, nil
}

// CreateBillingSubscription is the resolver for the createBillingSubscription field.
func (r *mutationResolver) OrderProductSubscription(ctx context.Context, productID int, currency model.Currency, interval model.PaymentInterval, autorenew bool, address map[string]interface{}, idempotencyKey *string) (model.PaymentIntent, error) {
	if err := billing.RequireEnabled(ctx); err != nil {
		return nil, err
	}

	if address == nil {
		// Perform a no-op billing address update if nil
		address = make(map[string]interface{})
	}

	// Update billing address first
	billingAddress, err := r.UpdateBillingAddress(ctx, address)
	if err != nil {
		return nil, err
	}

	var (
		sub    model.BillingSubscription
		intent model.PaymentIntent
	)
	userID := auth.ForContext(ctx).UserID
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		var retired bool
		row := tx.QueryRowContext(ctx, `
			SELECT retired
			FROM product
			WHERE id = $1
		`, productID)

		if err := row.Scan(&retired); err != nil {
			return err
		}
		if retired {
			return fmt.Errorf("this product is no longer available")
		}

		row = tx.QueryRowContext(ctx, `
		UPDATE subscription SET
			updated = NOW() at time zone 'utc',
			product_id = $2,
			currency = $3,
			interval = $4,
			autorenew = $5
		WHERE user_id = $1 AND status = 'PENDING'
		RETURNING
			id, user_id, product_id, created, updated,
			status, currency, interval, autorenew,
			payment_intent, payment_outcome, payment_error;
		`, userID, productID, currency, interval, autorenew)

		err := row.Scan(
			&sub.ID,
			&sub.UserID,
			&sub.ProductID,
			&sub.Created,
			&sub.Updated,
			&sub.Status,
			&sub.Currency,
			&sub.Interval,
			&sub.Autorenew,
			&sub.IntentID,
			&sub.Payment.Status,
			&sub.Payment.Error,
		)
		if err == sql.ErrNoRows {
			row = tx.QueryRowContext(ctx, `
			INSERT INTO subscription (
				created,
				updated,
				status,
				payment_outcome,
				user_id,
				product_id,
				currency,
				interval,
				autorenew
			) VALUES (
				NOW() at time zone 'utc',
				NOW() at time zone 'utc',
				'PENDING',
				'PENDING',
				$1,
				$2,
				$3,
				$4,
				$5
			) RETURNING
				id, user_id, product_id, created, updated,
				status, currency, interval, autorenew,
				payment_intent, payment_outcome, payment_error;
			`, userID, productID, currency, interval, autorenew)

			err = row.Scan(
				&sub.ID,
				&sub.UserID,
				&sub.ProductID,
				&sub.Created,
				&sub.Updated,
				&sub.Status,
				&sub.Currency,
				&sub.Interval,
				&sub.Autorenew,
				&sub.IntentID,
				&sub.Payment.Status,
				&sub.Payment.Error,
			)
			if err != nil {
				return err
			}
		} else if err != nil {
			return err
		}

		intent, err = billing.CreatePaymentIntent(ctx,
			&sub, billingAddress, idempotencyKey)
		if err != nil {
			return err
		}

		_, err = tx.ExecContext(ctx, `
		UPDATE subscription
		SET
			payment_intent = $2,
			payment_outcome = 'PENDING',
			payment_error = NULL
		WHERE id = $1
		`, sub.ID, intent.GetID())

		return err
	}); err != nil {
		return nil, err
	}

	return intent, nil
}

// BeginSubscriptionRenewal is the resolver for the beginSubscriptionRenewal field.
func (r *mutationResolver) BeginSubscriptionRenewal(ctx context.Context, subscriptionID int, idempotencyKey *string) (model.PaymentIntent, error) {
	if err := billing.RequireEnabled(ctx); err != nil {
		return nil, err
	}

	userID := auth.ForContext(ctx).UserID
	user, _ := loaders.ForContext(ctx).UsersByID.Load(userID)

	now := time.Now().UTC()
	if user.InternalPaymentDue == nil || user.InternalPaymentDue.After(now) {
		return nil, ErrNotPastDue
	}

	sub, err := loaders.ForContext(ctx).SubscriptionsByID.Load(subscriptionID)
	if err != nil {
		return nil, err
	}
	if sub == nil || sub.Status != model.SubscriptionStatusActive {
		return nil, ErrNoSubscription
	}

	var (
		addr   model.BillingAddress
		intent model.PaymentIntent
	)
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
			SELECT
				full_name, business_name, address_1, address_2,
				city, region, postcode, country, vat
			FROM "user"
			JOIN billing_address
				ON billing_address_id = billing_address.id
			WHERE "user".id = $1;
		`, userID)

		err := row.Scan(
			&addr.FullName,
			&addr.BusinessName,
			&addr.Address1,
			&addr.Address2,
			&addr.City,
			&addr.Region,
			&addr.Postcode,
			&addr.Country,
			&addr.Vat,
		)
		if err != nil && err != sql.ErrNoRows {
			return err
		}

		intent, err = billing.CreatePaymentIntent(
			ctx, sub, &addr, idempotencyKey)
		if err != nil {
			return err
		}

		_, err = tx.ExecContext(ctx, `
		UPDATE subscription
		SET
			payment_intent = $2,
			payment_outcome = 'PENDING',
			payment_error = NULL
		WHERE id = $1
		`, sub.ID, intent.GetID())
		return err
	}); err != nil {
		return nil, err
	}

	return intent, nil
}

// FinalizePaymentIntent is the resolver for the finalizePaymentIntent field.
func (r *mutationResolver) FinalizePaymentIntent(ctx context.Context, intentID string) (model.PaymentIntent, error) {
	sub, err := loaders.ForContext(ctx).SubscriptionsByIntent.Load(intentID)
	if err != nil {
		return nil, err
	}
	if sub == nil {
		return nil, gerrors.ErrNotFound
	}

	intent, err := billing.GetPaymentIntent(ctx, sub)
	if err != nil {
		return nil, err
	}
	if intent.GetOutcome().Status == model.PaymentIntentStatusCancelled {
		return intent, nil
	}

	userID := auth.ForContext(ctx).UserID
	user, _ := loaders.ForContext(ctx).UsersByID.Load(userID)

	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		return billing.ValidateSubscription(ctx, tx, user, sub, intent)
	}); err != nil {
		return intent, err
	}

	return intent, nil
}

// CreateSetupIntent is the resolver for the createSetupIntent field.
func (r *mutationResolver) CreateSetupIntent(ctx context.Context) (model.SetupIntent, error) {
	userID := auth.ForContext(ctx).UserID
	sub, err := loaders.ForContext(ctx).SubscriptionsByUserID.Load(userID)
	if err != nil {
		return nil, err
	}
	return billing.CreateSetupIntent(ctx, sub)
}

// FinalizeSetupIntent is the resolver for the finalizeSetupIntent field.
func (r *mutationResolver) FinalizeSetupIntent(ctx context.Context, intentID string) (model.SetupIntent, error) {
	userID := auth.ForContext(ctx).UserID
	sub, err := loaders.ForContext(ctx).SubscriptionsByUserID.Load(userID)
	if err != nil {
		return nil, err
	}

	intent, err := billing.GetSetupIntent(ctx, sub, intentID)
	if err != nil {
		return nil, err
	}

	if intent.GetStatus() != model.SetupIntentStatusSucceeded {
		return intent, nil
	}

	method := intent.GetMethod()
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
			INSERT INTO payment_method (
				currency,
				user_id,
				created,
				expires,
				name,
				processor_id
			) VALUES (
				$1, $2, $3, $4, $5, $6
			)
			ON CONFLICT ON CONSTRAINT payment_method_processor_id_key
			DO UPDATE SET name = $5
			RETURNING id;`,
			sub.Currency.String(),
			userID,
			method.Created,
			method.Expires,
			method.Name,
			method.ProcessorID)
		err := row.Scan(&method.ID)
		if err != nil {
			return err
		}

		_, err = tx.ExecContext(ctx, `
			UPDATE "user"
			SET default_payment_method_id = $2
			WHERE id = $1
		`, userID, method.ID)
		return err
	}); err != nil {
		return nil, err
	}

	return intent, nil
}

// ProcessPaymentDue is the resolver for the processPaymentDue field.
func (r *mutationResolver) ProcessPaymentDue(ctx context.Context) (model.PaymentIntent, error) {
	if err := billing.RequireEnabled(ctx); err != nil {
		return nil, err
	}

	var (
		err error
		sub *model.BillingSubscription
	)

	userID := auth.ForContext(ctx).UserID
	user, _ := loaders.ForContext(ctx).UsersByID.Load(userID)

	now := time.Now().UTC()
	if user.InternalPaymentDue == nil || user.InternalPaymentDue.After(now) {
		return nil, fmt.Errorf("account is not past due")
	}

	// Subsidized users don't have a subscription, but the end of their
	// subsidized term is processed through this resolver as a special case.
	if user.InternalPaymentStatus == model.PaymentStatusSubsidized {
		err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
			return billing.FinalizeCancellation(ctx, tx, user, nil)
		})
		return nil, err
	} else {
		sub, err = loaders.ForContext(ctx).SubscriptionsByUserID.Load(userID)
		if err != nil {
			return nil, err
		}
	}

	// Collect additional information for processing the payment
	var (
		addr   model.BillingAddress
		method model.PaymentMethod
	)
	if err := database.WithTx(ctx, &sql.TxOptions{
		ReadOnly:  true,
		Isolation: 0,
	}, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
			SELECT
				full_name, business_name, address_1, address_2,
				city, region, postcode, country, vat
			FROM "user"
			JOIN billing_address
				ON billing_address_id = billing_address.id
			WHERE "user".id = $1;
		`, userID)

		err := row.Scan(
			&addr.FullName,
			&addr.BusinessName,
			&addr.Address1,
			&addr.Address2,
			&addr.City,
			&addr.Region,
			&addr.Postcode,
			&addr.Country,
			&addr.Vat,
		)
		if err != nil {
			return err
		}

		row = tx.QueryRowContext(ctx, `
			SELECT id, currency, created, expires, name, processor_id
			FROM payment_method
			WHERE id = $1;
		`, *user.DefaultPaymentMethodID)

		return row.Scan(
			&method.ID,
			&method.Currency,
			&method.Created,
			&method.Expires,
			&method.Name,
			&method.ProcessorID)
	}); err != nil {
		return nil, err
	}

	var (
		intent  model.PaymentIntent
		outcome model.PaymentOutcome
	)

	// Idempotency: check if we already have a payment in flight for this
	// account, and if it was paid, apply the payment to the user's account.
	// Ensures that we don't double charge in the event that an internal
	// error occurs after collecting payment from the user.
	if sub.IntentID != nil {
		intent, err = billing.GetPaymentIntent(ctx, sub)
		if err != nil || !intent.GetOutcome().Charged() {
			// Abandon the in-flight intent if it was not completed
			intent = nil
		}
	}

	// Otherwise, charge the user and collect a fresh renewal payment intent
	if intent == nil {
		intent, err = billing.ChargeRenewalPayment(ctx, sub, &addr, &method)
	}

	if err != nil && err != billing.ErrCancelled {
		return nil, err
	} else if err == nil {
		// Update the in-flight payment intent in the database and
		// commit the transaction before doing anything else. This will
		// direct us to the sub.IntentID != nil branch above and retry
		// the subsequent steps without dobule-charging the user if an
		// error occurs in the remainder of this resolver.
		if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
			outcome := intent.GetOutcome()

			_, err = tx.ExecContext(ctx, `
			UPDATE subscription
			SET
				payment_intent = $2,
				payment_outcome = $3,
				payment_error = $4
			WHERE id = $1
			`, sub.ID, intent.GetID(), outcome.Status, outcome.Error)

			if err != nil && outcome.Charged() {
				panic(fmt.Errorf("error updating subscription %d occured after payment charged: %s",
					sub.ID, err.Error()))
			}

			return err
		}); err != nil {
			return nil, err
		}
	}

	// Finally, validate the user's subscription payment and apply the
	// changes to their account.
	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		if err == billing.ErrCancelled {
			return billing.FinalizeCancellation(ctx, tx, user, sub)
		}

		// ValidateSubscription won't process the payment unless the
		// subscription's intent ID matches the payment being validated
		sub.Status = model.SubscriptionStatusPending
		intentID := intent.GetID()
		sub.IntentID = &intentID

		return billing.ValidateSubscription(ctx, tx, user, sub, intent)
	}); err != nil {
		if outcome.Charged() {
			panic(fmt.Errorf("error updating subscription %d occured after payment charged: %s",
				sub.ID, err.Error()))
		}
		return nil, err
	}

	return intent, nil
}

// ReissueInvoice is the resolver for the reissueInvoice field.
func (r *mutationResolver) ReissueInvoice(ctx context.Context, id int) (*model.Invoice, error) {
	var invoice model.Invoice

	if err := database.WithTx(ctx, nil, func(tx *sql.Tx) error {
		row := tx.QueryRowContext(ctx, `
		SELECT
			id,
			invoice_no,
			issued,
			user_id,
			uuid,
			product_id,
			interval,
			service_start,
			service_end,
			currency,
			subtotal,
			tax_rate,
			tax_charged,
			reverse_vat,
			total
		FROM invoice
		WHERE id = $1
		`, id)

		if err := row.Scan(
			&invoice.ID,
			&invoice.InternalInvoiceNo,
			&invoice.Issued,
			&invoice.UserID,
			&invoice.UUID,
			&invoice.ProductID,
			&invoice.Interval,
			&invoice.ServiceStart,
			&invoice.ServiceEnd,
			&invoice.Currency,
			&invoice.Subtotal,
			&invoice.TaxRate,
			&invoice.TaxCharged,
			&invoice.ReverseVAT,
			&invoice.Total,
		); err != nil {
			return err
		}

		return billing.UploadInvoice(ctx, &invoice)
	}); err != nil {
		return nil, err
	}

	return &invoice, nil
}

